validation_rules.condition:
(
  SELECT COUNT(*) FROM landing_db.mrd_mbr_transactions WHERE cast(load_timestamp AS date) = current_date
) > 1.5 * (
  SELECT COUNT(*) FROM landing_db.mrd_mbr_transactions WHERE cast(load_timestamp AS date) = current_date - INTERVAL '1' DAY
)

(
  SELECT COUNT(*) FROM gold_db.dim_members WHERE member_status = 'ACTIVE'
) <> (
  SELECT COUNT(DISTINCT membership_number) FROM silver_db.mrd_mbr_info WHERE member_status = 'ACTIVE'
)

(
  SELECT COUNT(DISTINCT club_id) FROM landing_db.mrd_mbr_transactions WHERE cast(load_timestamp AS date) = current_date
) < 0.90 * (
  SELECT COUNT(DISTINCT club_id) FROM landing_db.mrd_mbr_transactions WHERE cast(load_timestamp AS date) = current_date - INTERVAL '1' DAY
)
